use std::collections::BinaryHeap;
use std::cmp::Reverse;

fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    let m = grid.len();
    let n = grid[0].len();
    let k = k as usize;
    let max_val = 10000;

    let mut dp = vec![vec![vec![i64::MAX; n]; m]; k + 1];
    dp[0][0][0] = 0;

    for t in 0..=k {
        let mut heap = BinaryHeap::new();
        for i in 0..m {
            for j in 0..n {
                if dp[t][i][j] != i64::MAX {
                    heap.push(Reverse((dp[t][i][j], i, j)));
                }
            }
        }

        while let Some(Reverse((cost, i, j))) = heap.pop() {
            if cost != dp[t][i][j] {
                continue;
            }

            if j + 1 < n {
                let ni = i;
                let nj = j + 1;
                let new_cost = cost + grid[ni][nj];
                if new_cost < dp[t][ni][nj] {
                    dp[t][ni][nj] = new_cost;
                    heap.push(Reverse((new_cost, ni, nj)));
                }
            }

            if i + 1 < m {
                let ni = i + 1;
                let nj = j;
                let new_cost = cost + grid[ni][nj];
                if new_cost < dp[t][ni][nj] {
                    dp[t][ni][nj] = new_cost;
                    heap.push(Reverse((new_cost, ni, nj)));
                }
            }
        }

        if t < k {
            let mut arr = vec![i64::MAX; max_val + 1];
            for i in 0..m {
                for j in 0..n {
                    if dp[t][i][j] == i64::MAX {
                        continue;
                    }
                    let val = grid[i][j] as usize;
                    if val <= max_val && dp[t][i][j] < arr[val] {
                        arr[val] = dp[t][i][j];
                    }
                }
            }

            let mut F = vec![i64::MAX; max_val + 1];
            F[max_val] = arr[max_val];
            for v in (0..max_val).rev() {
                F[v] = std::cmp::min(arr[v], F[v + 1]);
            }

            for i in 0..m {
                for j in 0..n {
                    let val = grid[i][j] as usize;
                    if val > max_val {
                        continue;
                    }
                    if F[val] < dp[t + 1][i][j] {
                        dp[t + 1][i][j] = F[val];
                    }
                }
            }
        }
    }

    let mut ans = i64::MAX;
    for t in 0..=k {
        if dp[t][m - 1][n - 1] < ans {
            ans = dp[t][m - 1][n - 1];
        }
    }
    ans
}
