    let m = grid.len();
    let n = grid[0].len();
    if m == 0 || n == 0 {
        return 0;
    }
    let max_val = 10000;
    let big_num: i64 = 1_i64 << 50;
    let k_usize = k as usize;
    let mut dp = vec![vec![vec![big_num; n]; m]; k_usize + 1];

    dp[0][0][0] = 0;
    for i in 0..m {
        for j in 0..n {
            if i == 0 && j == 0 {
                continue;
            }
            let mut cost = big_num;
            if i > 0 {
                cost = cost.min(dp[0][i-1][j] + grid[i][j]);
            }
            if j > 0 {
                cost = cost.min(dp[0][i][j-1] + grid[i][j]);
            }
            dp[0][i][j] = cost;
        }
    }

    if k_usize == 0 {
        return dp[0][m-1][n-1];
    }

    for t in 1..=k_usize {
        let mut min_dp_value = vec![big_num; max_val+1];
        for i in 0..m {
            for j in 0..n {
                let val = grid[i][j] as usize;
                if val <= max_val {
                    if dp[t-1][i][j] < min_dp_value[val] {
                        min_dp_value[val] = dp[t-1][i][j];
                    }
                }
            }
        }

        let mut suffix_min = vec![big_num; max_val+2];
        suffix_min[max_val] = min_dp_value[max_val];
        for v in (0..max_val).rev() {
            suffix_min[v] = min_dp_value[v].min(suffix_min[v+1]);
        }

        for i in 0..m {
            for j in 0..n {
                let val0 = grid[i][j] as usize;
                if val0 <= max_val {
                    dp[t][i][j] = suffix_min[val0];
                }
            }
        }

        for i in 0..m {
            for j in 0..n {
                if i > 0 {
                    let candidate = dp[t][i-1][j] + grid[i][j];
                    if candidate < dp[t][i][j] {
                        dp[t][i][j] = candidate;
                    }
                }
                if j > 0 {
                    let candidate = dp[t][i][j-1] + grid[i][j];
                    if candidate < dp[t][i][j] {
                        dp[t][i][j] = candidate;
                    }
                }
            }
        }
    }

    let mut ans = big_num;
    for t in 0..=k_usize {
        if dp[t][m-1][n-1] < ans {
            ans = dp[t][m-1][n-1];
        }
    }
    ans
}
