fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    let m = grid.len();
    let n = grid[0].len();
    let k = k as usize;
    const MAX_VAL: usize = 10000;

    let mut dp = vec![vec![vec![i64::MAX; k+1]; n]; m];
    dp[0][0][0] = 0;

    for t in 0..=k {
        for i in 0..m {
            for j in 0..n {
                let mut cost = i64::MAX;
                if i > 0 && dp[i-1][j][t] != i64::MAX {
                    cost = cost.min(dp[i-1][j][t] + grid[i][j]);
                }
                if j > 0 && dp[i][j-1][t] != i64::MAX {
                    cost = cost.min(dp[i][j-1][t] + grid[i][j]);
                }
                if cost != i64::MAX {
                    if cost < dp[i][j][t] {
                        dp[i][j][t] = cost;
                    }
                }
            }
        }

        if t < k {
            let mut min_of_value = vec![i64::MAX; MAX_VAL + 1];
            for i in 0..m {
                for j in 0..n {
                    if dp[i][j][t] == i64::MAX {
                        continue;
                    }
                    let v = grid[i][j] as usize;
                    if v <= MAX_VAL {
                        if dp[i][j][t] < min_of_value[v] {
                            min_of_value[v] = dp[i][j][t];
                        }
                    }
                }
            }

            let mut min_arr = vec![i64::MAX; MAX_VAL + 2];
            min_arr[MAX_VAL] = min_of_value[MAX_VAL];
            for v in (0..MAX_VAL).rev() {
                min_arr[v] = min_of_value[v].min(min_arr[v + 1]);
            }

            for i in 0..m {
                for j in 0..n {
                    let val = grid[i][j] as usize;
                    if val <= MAX_VAL && min_arr[val] != i64::MAX {
                        if min_arr[val] < dp[i][j][t + 1] {
                            dp[i][j][t + 1] = min_arr[val];
                        }
                    }
                }
            }
        }
    }

    *dp[m - 1][n - 1].iter().min().unwrap()
}
```

